Adv.talkWithFacial(nil,nil,ND2BCh3,[[Allies approaching from 3 o'clock. It's 30-G and the engineering corps.]],"VC_MC02_24_07_04_Novel_00000_YIzumi")
Adv.talkWithFacial(nil,nil,IODBg,[[Sure took 'em a while.]],"VC_MC02_24_07_04_Novel_00001_MAikawa")Sound.stopBGM(1)
Layout.createStageFixBg(JQT,Position.BG_RIGHT)Layout.show(AtYtR)
Adv.talkWithFacial(nil,nil,AtYtR,[[Nice, nice. We're all finally united!]],"VC_MC02_24_07_04_Novel_00002_RKayamori")
