Sound.playBGM("SB0025",1)Wait(1)Layout.show({YRDu,"070201"})
Adv.talkWithFacial(nil,nil,YRDu,[[Sorry for the delay.]],"VC_MC02_24_07_04_Novel_00003_YShirakawa")
