Layout.show({CWRiP,"070201"},{LB0A,"000202"})
Adv.talkWithFacial(nil,nil,CWRiP,[[Seems like we kept you waiting.]],"VC_MC02_24_07_04_Novel_00004_SKura")
Adv.talkWithFacial("000001",nil,LB0A,[[My sincere apologies.]],"VC_MC02_24_07_04_Novel_00005_MTsukishiro")
Layout.setup(Layout.createStageFixBg(JQT,Position.BG_RIGHT),AtYtR)Layout.show(AtYtR)
Adv.talkWithFacial(nil,nil,AtYtR,[[Nah, it's fine. The roads were pretty bad, weren't they? How was it?]],"VC_MC02_24_07_04_Novel_00006_RKayamori")
Layout.show({AtYtR,"000301"},{YRDu,"070001"})
Adv.talkWithFacial(nil,nil,YRDu,[[In quite terrible shape. The abandoned regions have fallen into greater disrepair than expected.]],"VC_MC02_24_07_04_Novel_00007_YShirakawa")
Adv.talkWithFacial("070101",nil,YRDu,[[Removing obstacles from the path was exactly the same as in training, but the sheer amount was a struggle to deal with.]],"VC_MC02_24_07_04_Novel_00008_YShirakawa")Layout.createStageFixBg(JQT,Position.BG_LEFT)
Layout.show({CWRiP,"070202"})
Adv.talkWithFacial(nil,nil,CWRiP,[[There were a lot of cracks in the ground, too.]],"VC_MC02_24_07_04_Novel_00009_SKura")
Adv.talkWithFacial("070002",nil,CWRiP,[[We worked with the engineering corps to secure the paths so we could proceed, but it was barely enough to let the convoys through. It took a long time.]],"VC_MC02_24_07_04_Novel_00010_SKura")Layout.createStageFixBg(JQT,Position.BG_RIGHT)
Layout.show({AtYtR,"000201"},{YRDu,"070201"})
Adv.talkWithFacial(nil,nil,AtYtR,[[Woah, that sounds like it was a doozy.]],"VC_MC02_24_07_04_Novel_00011_RKayamori")
Adv.act(AtYtR,"000301",AdvCharacterMouth.Mouth01,0.4)
Adv.talkWithFacial("000101",nil,YRDu,[[I'm afraid things won't get much easier from here.]],"VC_MC02_24_07_04_Novel_00012_YShirakawa")
Adv.talkWithFacial("000003",nil,YRDu,[[I've heard from the commander that the roads ahead may have portions that the convoys can't traverse.]],"VC_MC02_24_07_04_Novel_00013_YShirakawa")
Adv.talkWithFacial(nil,nil,YRDu,[[We'll do our best to secure the path as we move ahead, but there will still be a large burden on your squad.]],"VC_MC02_24_07_04_Novel_00014_YShirakawa")
Adv.act(YRDu,"000103",AdvCharacterMouth.Mouth01,0.4)
Adv.talkWithFacial("000302",nil,AtYtR,[[We'll be fine! We covered a lot of cases with convoy troubles in training, so it's no sweat.]],"VC_MC02_24_07_04_Novel_00018_RKayamori")
Adv.talkWithFacial("010003",nil,YRDu,[[Mm... That's good to hear.]],"VC_MC02_01006_v001_YShirakawa")
Adv.talkWithFacial("000302",nil,AtYtR,[[Alright, let's continue the operation.]],"VC_MC02_24_07_04_Novel_00020_RKayamori")
Adv.talkWithFacial("070101",nil,YRDu,[[Right. 30-G will continue ahead on Route 246, removing blockages and obstacles. We should aid the path-laying.]],"VC_MC02_01007_v001_YShirakawa")
Adv.talkWithFacial(nil,nil,YRDu,[[31-A, I want you to take over the escort for the engineering corps and the convoy.]],"VC_MC02_24_07_04_Novel_00023_YShirakawa")
Adv.talkWithFacial("070301",nil,AtYtR,[[Roger that. 31-A is taking over the escort.]],"VC_MC02_24_07_04_Novel_00024_RKayamori")
Adv.talkWithFacial(nil,nil,YRDu,[[We're counting on you.]],"VC_MC02_24_07_04_Novel_00025_YShirakawa")
Adv.talkWithFacial(nil,nil,AtYtR,[[Leave it to me!]],"VC_MC02_24_07_04_Novel_00026_RKayamori")Sound.stopBGM(1)Exit_Novel()